from flask import Flask, request
import time
from prometheus_client import start_http_server, Counter, Histogram

app = Flask(__name__)

# Prometheus metrics setup
REQUEST_LATENCY = Histogram('request_latency_seconds', 'Time spent processing request')
REQUEST_COUNT = Counter('request_count_total', 'Total number of requests')
USER_REQUESTS = Counter('user_requests_total', 'Number of requests per user', ['user_id'])
API_KEY_REQUESTS = Counter('api_key_requests_total', 'Number of requests per API key', ['api_key'])

@app.before_request
def start_timer():
    request.start_time = time.time()

@app.after_request
def log_request(response):
    duration = time.time() - request.start_time
    REQUEST_LATENCY.observe(duration)
    REQUEST_COUNT.inc()
    
    user_id = request.headers.get('User-ID')
    api_key = request.headers.get('API-Key')
    
    if user_id:
        USER_REQUESTS.labels(user_id=user_id).inc()
    
    if api_key:
        API_KEY_REQUESTS.labels(api_key=api_key).inc()
    
    return response

@app.route('/metrics', methods=['GET'])
def metrics():
    return '', 204

if __name__ == '__main__':
    start_http_server(8000)
    app.run(host='0.0.0.0', port=5000)